def eliminate_left_recursion(productions):
    '''Eliminate direct left recursion from grammar'''
    new_productions = {}

    for non_terminal, rules in productions.items():
        alpha = []  # Rules with recursion
        beta = []   # Rules without recursion

        for rule in rules:
            if rule and rule[0] == non_terminal:
                alpha.append(rule[1:])  # After the left-recursive part
            else:
                beta.append(rule)

        if alpha:
            # Create new non-terminal
            new_nt = non_terminal + "'"
            new_productions[non_terminal] = [r + new_nt for r in beta]
            new_productions[new_nt] = [r + new_nt for r in alpha] + ['ε']
        else:
            new_productions[non_terminal] = rules

    return new_productions

