def left_factoring(productions):
    '''Perform left factoring to make grammar suitable for LL(1) parsing'''
    new_productions = {}

    for nt, rules in productions.items():
        if len(rules) <= 1:
            new_productions[nt] = rules
            continue

        # Find longest common prefix among all rules
        prefix = rules[0]
        for r in rules[1:]:
            while prefix and not r.startswith(prefix):
                prefix = prefix[:-1]

        if len(prefix) > 0:
            # Factor out the prefix
            remaining = [r[len(prefix):] if r[len(prefix):] else 'ε' 
                        for r in rules]
            new_nt = nt + "'"
            new_productions[nt] = [prefix + new_nt]
            new_productions[new_nt] = remaining
        else:
            new_productions[nt] = rules

    return new_productions

