def cyk_parse(string, grammar_cnf):
    '''
    CYK algorithm to check if string is generated by CFG in CNF
    grammar_cnf: dict of {non_terminal: [set of terminals/non-terminals]}
    '''
    n = len(string)
    if n == 0:
        return 'ε' in grammar_cnf.get('S', set())

    # DP table: table[i][j] = set of non-terminals deriving substring i to j
    table = [[set() for _ in range(n)] for _ in range(n)]

    # Fill diagonal with terminals
    for i, char in enumerate(string):
        for nt, rules in grammar_cnf.items():
            if char in rules:
                table[i][i].add(nt)

    # Fill rest of table
    for length in range(2, n + 1):
        for i in range(n - length + 1):
            j = i + length - 1
            for k in range(i, j):
                for nt, rules in grammar_cnf.items():
                    for rule in rules:
                        if len(rule) == 2:  # B C form
                            B, C = rule
                            if B in table[i][k] and C in table[k+1][j]:
                                table[i][j].add(nt)

    return 'S' in table[0][n-1]

